SELECT COUNT(*)
FROM skill_package
WHERE id = #{packageId}
  AND version = #{packageVersion}

SELECT
    BIN_TO_UUID(id) AS loadId,
    capability_type AS capabilityType,
    CAST(descriptor_json AS CHAR) AS descriptorJson
FROM capability_load
WHERE loop_node_id =
    #{loopNodeId,typeHandler=com.funjson.metaagent.common.persistence.mybatis.UuidBinaryTypeHandler}
  AND source_id = #{sourceId}
  AND source_version = #{sourceVersion}
  AND status = 'APPLIED'
